const accountNumber = $json.account_number || 'UNKNOWN';
const planName = $json.plan_name || 'UNKNOWN';
const effectiveDate = $json.effective_date || new Date().toISOString().split('T')[0];

return [{
  json: {
    status: "SUCCESS",
    message: `Plan ${planName} activated for account ${accountNumber}`,
    effective_date: effectiveDate,
    confirmation_code: `XFC-ACT-${Date.now()}`,
    next_billing_date: "2025-04-01",
    notes: "Customer will receive SMS confirmation within 5 minutes"
  }
}];

const accountNumber = $json.account_number || 'UNKNOWN';
const address = $json.address || 'UNKNOWN';
const preferredDate = $json.preferred_date || 'Next available';

return [{
  json: {
    status: "SUCCESS",
    message: `Installation scheduled for ${address}`,
    account_number: accountNumber,
    schedule: {
      date: preferredDate,
      time_slot: "9:00 AM - 12:00 PM",
      technician: "Team Bravo",
      reference: `XFC-INST-${Date.now()}`
    },
    requirements: "Customer must be present. Ensure clear access to fiber entry point.",
    notes: "Confirmation SMS sent to registered mobile number"
  }
}];

const accountNumber = $json.account_number || 'UNKNOWN';
const reason = $json.reason || 'Customer request';
const oldSim = $json.old_sim || 'UNKNOWN';

return [{
  json: {
    status: "SUCCESS",
    message: `SIM swap processed for account ${accountNumber}`,
    old_sim_status: "BLOCKED",
    new_sim_status: "PENDING_ACTIVATION",
    reference: `XFC-SIM-${Date.now()}`,
    gcash_alert: "xCash team notified — account temporarily locked for security",
    activation_eta: "Within 24 hours",
    monitoring: "30-day fraud monitoring activated",
    notes: `Reason: ${reason}. Verification completed.`
  }
}];
